function car_table_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('car_table');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'car_number' => Request::val('car_number', ''),
		'registration_number' => Request::val('registration_number', ''),
		'car_model' => Request::val('car_model', ''),
		'car_vin' => Request::val('car_vin', ''),
		'fuel_type' => Request::val('fuel_type', ''),
		'seating_capacity' => Request::val('seating_capacity', ''),
		'car_color' => Request::val('car_color', ''),
		'rental_company_name' => Request::val('rental_company_name', ''),
		'contact_person' => Request::val('contact_person', ''),
		'contact_number_of_person' => Request::val('contact_number_of_person', ''),
		'rental_rate' => Request::val('rental_rate', ''),
		'rental_start_date' => Request::dateComponents('rental_start_date', '1'),
		'rental_end_date' => Request::dateComponents('rental_end_date', ''),
		'purpose' => br2nl(Request::val('purpose', '')),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('car_table', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		car_table_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function car_table_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

function car_table_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('car_table', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: car_table_before_delete
	if(function_exists('car_table_before_delete')) {
		$args = [];
		if(!car_table_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	// child table: car_usage_table
	$res = sql("SELECT `id` FROM `car_table` WHERE `id`='{$selected_id}'", $eo);
	$id = db_fetch_row($res);
	$rires = sql("SELECT COUNT(1) FROM `car_usage_table` WHERE `car_lookup`='" . makeSafe($id[0]) . "'", $eo);
	$rirow = db_fetch_row($rires);
	$childrenATag = '<a class="alert-link" href="car_usage_table_view.php?filterer_car_lookup=' . urlencode($id[0]) . '">%s</a>';
	if($rirow[0] && !$AllowDeleteOfParents && !$skipChecks) {
		$RetMsg = $Translation["couldn't delete"];
		$RetMsg = str_replace('<RelatedRecords>', sprintf($childrenATag, $rirow[0]), $RetMsg);
		$RetMsg = str_replace(['[<TableName>]', '<TableName>'], sprintf($childrenATag, 'car_usage_table'), $RetMsg);
		return $RetMsg;
	} elseif($rirow[0] && $AllowDeleteOfParents && !$skipChecks) {
		$RetMsg = $Translation['confirm delete'];
		$RetMsg = str_replace('<RelatedRecords>', sprintf($childrenATag, $rirow[0]), $RetMsg);
		$RetMsg = str_replace(['[<TableName>]', '<TableName>'], sprintf($childrenATag, 'car_usage_table'), $RetMsg);
		$RetMsg = str_replace('<Delete>', '<input type="button" class="btn btn-danger" value="' . html_attr($Translation['yes']) . '" onClick="window.location = `car_table_view.php?SelectedID=' . urlencode($selected_id) . '&delete_x=1&confirmed=1&csrf_token=' . urlencode(csrf_token(false, true)) . (Request::val('Embedded') ? '&Embedded=1' : '') . '`;">', $RetMsg);
		$RetMsg = str_replace('<Cancel>', '<input type="button" class="btn btn-success" value="' . html_attr($Translation[ 'no']) . '" onClick="window.location = `car_table_view.php?SelectedID=' . urlencode($selected_id) . (Request::val('Embedded') ? '&Embedded=1' : '') . '`;">', $RetMsg);
		return $RetMsg;
	}

	sql("DELETE FROM `car_table` WHERE `id`='{$selected_id}'", $eo);

	// hook: car_table_after_delete
	if(function_exists('car_table_after_delete')) {
		$args = [];
		car_table_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='car_table' AND `pkValue`='{$selected_id}'", $eo);
}

function car_table_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('car_table', $selected_id, 'edit')) return false;

	$data = [
		'car_number' => Request::val('car_number', ''),
		'registration_number' => Request::val('registration_number', ''),
		'car_model' => Request::val('car_model', ''),
		'car_vin' => Request::val('car_vin', ''),
		'fuel_type' => Request::val('fuel_type', ''),
		'seating_capacity' => Request::val('seating_capacity', ''),
		'car_color' => Request::val('car_color', ''),
		'rental_company_name' => Request::val('rental_company_name', ''),
		'contact_person' => Request::val('contact_person', ''),
		'contact_number_of_person' => Request::val('contact_number_of_person', ''),
		'rental_rate' => Request::val('rental_rate', ''),
		'rental_start_date' => Request::dateComponents('rental_start_date', ''),
		'rental_end_date' => Request::dateComponents('rental_end_date', ''),
		'purpose' => br2nl(Request::val('purpose', '')),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	// get existing values
	$old_data = getRecord('car_table', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: car_table_before_update
	if(function_exists('car_table_before_update')) {
		$args = ['old_data' => $old_data];
		if(!car_table_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'car_table',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="car_table_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('car_table', $data['selectedID'], calculated_fields()['car_table']);

	// hook: car_table_after_update
	if(function_exists('car_table_after_update')) {
		if($row = getRecord('car_table', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!car_table_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('car_table', $selected_id);
}

